    30→SDL_Surface* InitializeSDL( int width, int height, bool fullscreen )
    31→{
    32→	if ( SDL_Init( SDL_INIT_VIDEO | SDL_INIT_TIMER ) < 0 )
    33→	{
    34→		std::cout << "Could not init SDL: " << SDL_GetError() << std::endl;
    35→		exit(1);
    36→	}
    37→	atexit( SDL_Quit );
    38→
    39→	Uint32 flags = SDL_SWSURFACE;
    40→	if ( fullscreen )
    41→		flags |= SDL_FULLSCREEN;
    42→
    43→	SDL_Surface* surface = 0;
    44→	surface = SDL_SetVideoMode( width, height, 32, flags );
    45→	if ( surface == 0 )
    46→	{
    47→		std::cout << "Could not set video mode: "
    48→		          << SDL_GetError() << std::endl;
    49→		exit(1);
    50→	}
    51→	return surface;
    52→}
