    54→bool NoQuitMessageSDL()
    55→{
    56→	SDL_Event e;
    57→	while ( SDL_PollEvent(&e) )
    58→	{
    59→		if ( e.type == SDL_QUIT )
    60→			return false;
    61→		if ( e.type == SDL_KEYDOWN )
    62→			if ( e.key.keysym.sym == SDLK_ESCAPE)
    63→				return false;
    64→	}
    65→	return true;
    66→}
