    69→void PutPixelSDL( SDL_Surface* surface, int x, int y, glm::vec3 color )
    70→{
    71→	if ( x < 0 || surface->w <= x || y < 0 || surface->h <= y )
    72→		return;
    73→
    74→	Uint8 r = Uint8( glm::clamp( 255 * color.r, 0.f, 255.f ) );
    75→	Uint8 g = Uint8( glm::clamp( 255 * color.g, 0.f, 255.f ) );
    76→	Uint8 b = Uint8( glm::clamp( 255 * color.b, 0.f, 255.f ) );
    77→
    78→	Uint32* p = (Uint32*)surface->pixels + y * surface->pitch / 4 + x;
    79→	*p = SDL_MapRGB( surface->format, r, g, b );
    80→}
