    33→// Loads the Cornell Box. It is scaled to fill the volume:
    34→// -1 <= x <= +1
    35→// -1 <= y <= +1
    36→// -1 <= z <= +1
    37→void LoadTestModel( std::vector<Triangle>& triangles )
    38→{
    39→	using glm::vec3;
    40→
    41→	// Defines colors:
    42→	vec3 red(    0.75f, 0.15f, 0.15f );
    43→	vec3 yellow( 0.75f, 0.75f, 0.15f );
