    45→	vec3 cyan(   0.15f, 0.75f, 0.75f );
    46→	vec3 blue(   0.15f, 0.15f, 0.75f );
    47→	vec3 purple( 0.75f, 0.15f, 0.75f );
    48→	vec3 white(  0.75f, 0.75f, 0.75f );
    49→
    50→	triangles.clear();
    51→	triangles.reserve( 5 * 2 * 3 );
    52→
    53→	// ---------------------------------------------------------------------------
    54→	// Room
    55→
    56→	float L = 555;			// Length of Cornell Box side.
    57→
    58→	vec3 A(L, 0, 0);
    59→	vec3 B(0, 0, 0);
    60→	vec3 C(L, 0, L);
    61→	vec3 D(0, 0, L);
    62→
    63→	vec3 E(L, L, 0);
    64→	vec3 F(0, L, 0);
    65→	vec3 G(L, L, L);
    66→	vec3 H(0, L, L);
    67→
    68→	// Floor:
    69→	triangles.push_back( Triangle( C, B, A, green ) );
    70→	triangles.push_back( Triangle( C, D, B, green ) );
    71→
    72→	// Left wall
    73→	triangles.push_back( Triangle( A, E, C, purple ) );
    74→	triangles.push_back( Triangle( C, E, G, purple ) );
    75→
    76→	// Right wall
    77→	triangles.push_back( Triangle( F, B, D, yellow ) );
    78→	triangles.push_back( Triangle( H, F, D, yellow ) );
    79→
    80→	// Ceiling
    81→	triangles.push_back( Triangle( E, F, G, cyan ) );
    82→	triangles.push_back( Triangle( F, H, G, cyan ) );
    83→
    84→	// Back wall
    85→	triangles.push_back( Triangle( G, D, C, white ) );
    86→	triangles.push_back( Triangle( G, H, D, white ) );
    87→
    88→	// ---------------------------------------------------------------------------
    89→	// Short block
    90→
    91→	A = vec3(290, 0, 114);
    92→	B = vec3(130, 0, 65);
    93→	C = vec3(240, 0, 272);
    94→	D = vec3( 82, 0, 225);
    95→
    96→	E = vec3(290, 165, 114);
    97→	F = vec3(130, 165, 65);
    98→	G = vec3(240, 165, 272);
    99→	H = vec3( 82, 165, 225);
   100→
   101→	// Front
   102→	triangles.push_back( Triangle(E, B, A, red) );
   103→	triangles.push_back( Triangle(E, F, B, red) );
   104→
   105→	// Front
   106→	triangles.push_back( Triangle(F, D, B, red) );
   107→	triangles.push_back( Triangle(F, H, D, red) );
   108→
   109→	// BACK
   110→	triangles.push_back( Triangle(H, C, D, red) );
   111→	triangles.push_back( Triangle(H, G, C, red) );
   112→
   113→	// LEFT
   114→	triangles.push_back( Triangle(G, E, C, red) );
   115→	triangles.push_back( Triangle(E, A, C, red) );
   116→
   117→	// TOP
   118→	triangles.push_back( Triangle(G, F, E, red) );
   119→	triangles.push_back( Triangle(G, H, F, red) );
   120→
   121→	// ---------------------------------------------------------------------------
   122→	// Tall block
   123→
   124→	A = vec3(423, 0, 247);
   125→	B = vec3(265, 0, 296);
   126→	C = vec3(472, 0, 406);
   127→	D = vec3(314, 0, 456);
   128→
   129→	E = vec3(423, 330, 247);
   130→	F = vec3(265, 330, 296);
   131→	G = vec3(472, 330, 406);
   132→	H = vec3(314, 330, 456);
   133→
   134→	// Front
   135→	triangles.push_back( Triangle(E, B, A, blue) );
   136→	triangles.push_back( Triangle(E, F, B, blue) );
   137→
   138→	// Front
   139→	triangles.push_back( Triangle(F, D, B, blue) );
   140→	triangles.push_back( Triangle(F, H, D, blue) );
   141→
   142→	// BACK
   143→	triangles.push_back( Triangle(H, C, D, blue) );
   144→	triangles.push_back( Triangle(H, G, C, blue) );
   145→
   146→	// LEFT
   147→	triangles.push_back( Triangle(G, E, C, blue) );
   148→	triangles.push_back( Triangle(E, A, C, blue) );
   149→
   150→	// TOP
   151→	triangles.push_back( Triangle(G, F, E, blue) );
   152→	triangles.push_back( Triangle(G, H, F, blue) );
   153→
   154→
   155→	// ----------------------------------------------
   156→	// Scale to the volume [-1,1]^3
   157→
   158→	for ( size_t i = 0; i < triangles.size(); ++i )
   159→	{
   160→		triangles[i].v0 *= 2 / L;
   161→		triangles[i].v1 *= 2 / L;
   162→		triangles[i].v2 *= 2 / L;
   163→
   164→		triangles[i].v0 -= vec3(1, 1, 1);
   165→		triangles[i].v1 -= vec3(1, 1, 1);
   166→		triangles[i].v2 -= vec3(1, 1, 1);
   167→
   168→		triangles[i].v0.x *= -1;
   169→		triangles[i].v1.x *= -1;
   170→		triangles[i].v2.x *= -1;
   171→
   172→		triangles[i].v0.y *= -1;
   173→		triangles[i].v1.y *= -1;
   174→		triangles[i].v2.y *= -1;
   175→
   176→		triangles[i].ComputeNormal();
   177→	}
   178→}
   179→
   180→#endif

