    59→inline bool RayTriangleIntersection(const vec3& orig,
    60→                                    const vec3& dir,
    61→                                    const vec3& v0,
    62→                                    const vec3& v1,
    63→                                    const vec3& v2,
    64→                                    float& t,
    65→                                    float& u,
    66→                                    float& v)
    67→{
    68→    const float EPSILON = 1e-6f;
    69→    vec3 e1 = v1 - v0;
    70→    vec3 e2 = v2 - v0;
    71→    vec3 pvec = glm::cross(dir, e2);
    72→    float det = glm::dot(e1, pvec);
    73→    if (fabs(det) < EPSILON)
    74→        return false;
    75→
    76→    float invDet = 1.0f / det;
    77→    vec3 tvec = orig - v0;
    78→    u = glm::dot(tvec, pvec) * invDet;
    79→    if (u < 0.0f || u > 1.0f)
    80→        return false;
    81→
    82→    vec3 qvec = glm::cross(tvec, e1);
    83→    v = glm::dot(dir, qvec) * invDet;
    84→    if (v < 0.0f || u + v > 1.0f)
    85→        return false;
    86→
    87→    t = glm::dot(e2, qvec) * invDet;
    88→    return t > 0.0f;
    89→}
