    13→using glm::vec3;
    14→
    15→const vec3 kSnakeColor(0.0f, 1.0f, 0.0f);
    16→const vec3 kFoodColor (1.0f, 0.0f, 0.0f);
    17→
    18→// Grid configuration
    19→constexpr int kGridWidth  = 20;
    20→constexpr int kGridHeight = 20;
    21→constexpr int kCellSize   = 15;
    22→
    23→// Game state
    24→SDL_Surface* screen = nullptr;
    25→
    26→using Cell = std::pair<int, int>;
    27→
    28→std::deque<Cell> snake;
    29→Cell food;
    30→
    31→// Occupancy grid to accelerate collision checks
    32→bool occupied[kGridHeight][kGridWidth];
    33→
    34→int directionX = 1;
    35→int directionY = 0;
    36→bool isAlive   = true;
    37→
    38→void SpawnFood()
    39→{
    40→    int x, y;
    41→
    42→    // Ensure food never spawns on the snake body
    43→    do
    44→    {
    45→        x = rand() % kGridWidth;
    46→        y = rand() % kGridHeight;
    47→    }
    48→    while (occupied[y][x]);
    49→
    50→    food = Cell(x, y);
    51→}
    52→
    53→void DrawCell(int gridX, int gridY, const vec3& color)
    54→{
    55→    SDL_Rect rect;
    56→    rect.x = gridX * kCellSize;
    57→    rect.y = gridY * kCellSize;
    58→    rect.w = kCellSize;
    59→    rect.h = kCellSize;
    60→
    61→    const float rClamped = glm::clamp(color.r, 0.0f, 1.0f);
    62→    const float gClamped = glm::clamp(color.g, 0.0f, 1.0f);
    63→    const float bClamped = glm::clamp(color.b, 0.0f, 1.0f);
    64→
    65→    const Uint8 r = static_cast<Uint8>(rClamped * 255.0f);
    66→    const Uint8 g = static_cast<Uint8>(gClamped * 255.0f);
    67→    const Uint8 b = static_cast<Uint8>(bClamped * 255.0f);
    68→
    69→    const Uint32 mapped = SDL_MapRGB(screen->format, r, g, b);
    70→    SDL_FillRect(screen, &rect, mapped);
    71→}
    72→
    73→void UpdateSnake()
    74→{
    75→    const Cell& head = snake.front();
    76→    const int newX   = head.first  + directionX;
    77→    const int newY   = head.second + directionY;
    78→
    79→    const bool hitWall =
    80→        newX < 0 || newX >= kGridWidth ||
    81→        newY < 0 || newY >= kGridHeight;
    82→
    83→    if (hitWall)
    84→    {
    85→        isAlive = false;
    86→        return;
    87→    }
    88→
    89→    const bool willGrow = (newX == food.first && newY == food.second);
    90→
    91→    // If we're not growing, free the tail cell so moving into the old tail
    92→    // position is allowed in the same step.
    93→    if (!willGrow)
    94→    {
    95→        const Cell& tail = snake.back();
    96→        occupied[tail.second][tail.first] = false;
    97→        snake.pop_back();
    98→    }
    99→
   100→    // Self-collision check using occupancy grid (O(1))
   101→    if (occupied[newY][newX])
   102→    {
   103→        isAlive = false;
   104→        return;
   105→    }
   106→
   107→    const Cell newHead(newX, newY);
   108→    snake.push_front(newHead);
   109→    occupied[newY][newX] = true;
   110→
   111→    if (willGrow)
   112→    {
   113→        SpawnFood();
   114→    }
   115→}
   116→
   117→void HandleInput()
   118→{
   119→    SDL_Event event;
   120→
   121→    while (SDL_PollEvent(&event))
   122→    {
   123→        if (event.type == SDL_QUIT)
   124→        {
   125→            isAlive = false;
   126→            continue;
   127→        }
   128→
   129→        if (event.type != SDL_KEYDOWN)
   130→        {
   131→            continue;
   132→        }
   133→
   134→        SDLKey key = event.key.keysym.sym;
   135→
   136→        if (key == SDLK_ESCAPE)
   137→        {
   138→            isAlive = false;
   139→        }
   140→        else if (key == SDLK_UP && directionY == 0)
   141→        {
   142→            directionX = 0;
   143→            directionY = -1;
   144→        }
   145→        else if (key == SDLK_DOWN && directionY == 0)
   146→        {
   147→            directionX = 0;
   148→            directionY = 1;
   149→        }
   150→        else if (key == SDLK_LEFT && directionX == 0)
   151→        {
   152→            directionX = -1;
   153→            directionY = 0;
   154→        }
   155→        else if (key == SDLK_RIGHT && directionX == 0)
   156→        {
   157→            directionX = 1;
   158→            directionY = 0;
   159→        }
   160→    }
   161→}
   162→
   163→void Render()
   164→{
   165→    SDL_FillRect(screen, nullptr, 0);
   166→
   167→    if (SDL_MUSTLOCK(screen))
   168→    {
   169→        SDL_LockSurface(screen);
   170→    }
   171→
   172→    // Draw snake body (green)
   173→    for (const Cell& segment : snake)
   174→    {
   175→        DrawCell(segment.first, segment.second, kSnakeColor);
   176→    }
   177→
   178→    // Draw food (red)
   179→    DrawCell(food.first, food.second, kFoodColor);
   180→
   181→    if (SDL_MUSTLOCK(screen))
   182→    {
   183→        SDL_UnlockSurface(screen);
   184→    }
   185→
   186→    SDL_UpdateRect(screen, 0, 0, 0, 0);
   187→}
   188→
   189→int main(int /*argc*/, char** /*argv*/)
   190→{
   191→    srand(static_cast<unsigned int>(time(nullptr)));
   192→
   193→    screen = InitializeSDL(kGridWidth * kCellSize, kGridHeight * kCellSize);
   194→
   195→    snake.clear();
   196→
   197→    // Reset occupancy grid
   198→    std::memset(occupied, 0, sizeof(occupied));
   199→
   200→    snake.push_back(Cell(kGridWidth / 2, kGridHeight / 2));
   201→    occupied[snake.front().second][snake.front().first] = true;
   202→
   203→    SpawnFood();
   204→
   205→    Uint32 lastUpdateTime = SDL_GetTicks();
   206→
   207→    while (isAlive)
   208→    {
   209→        HandleInput();
   210→
   211→        Uint32 now = SDL_GetTicks();
   212→        if (now - lastUpdateTime > 120)
   213→        {
   214→            UpdateSnake();
   215→            lastUpdateTime = now;
   216→        }
   217→
   218→        Render();
   219→        SDL_Delay(10);
   220→    }
   221→
   222→    return 0;
   223→}
