     4→void bubble_sort(std::vector<int>& data)
     5→{
     6→    const std::size_t n = data.size();
     7→    if (n < 2) return;
     8→
     9→    for (std::size_t i = 0; i + 1 < n; ++i)
    10→    {
    11→        bool swapped = false;
    12→        for (std::size_t j = 0; j + 1 < n - i; ++j)
    13→        {
    14→            if (data[j] > data[j + 1])
    15→            {
    16→                std::swap(data[j], data[j + 1]);
    17→                swapped = true;
    18→            }
    19→        }
    20→        if (!swapped) break;
    21→    }
    22→}
    23→
    24→int main()
    25→{
    26→    std::vector<int> arr{5, 1, 4, 2, 8};
    27→    bubble_sort(arr);
    28→
    29→    for (std::size_t i = 0; i < arr.size(); ++i)
    30→    {
    31→        std::cout << arr[i] << (i + 1 == arr.size() ? '\n' : ' ');
    32→    }
    33→
    34→    return 0;
    35→}
