            directionX = 0;
            directionY = 1;
        }
        else if (key == SDLK_LEFT && directionX == 0)
        {
            directionX = -1;
            directionY = 0;
        }
        else if (key == SDLK_RIGHT && directionX == 0)
        {
            directionX = 1;
            directionY = 0;
        }
    }
}

void Render()
{
    SDL_FillRect(screen, nullptr, 0);

