    }

    // Draw food (red)
    DrawCell(food.first, food.second, kFoodColor);

    if (SDL_MUSTLOCK(screen))
    {
        SDL_UnlockSurface(screen);
    }

    SDL_UpdateRect(screen, 0, 0, 0, 0);
}

int main(int /*argc*/, char** /*argv*/)
{
