    std::memset(occupied, 0, sizeof(occupied));

    snake.push_back(Cell(kGridWidth / 2, kGridHeight / 2));
    occupied[snake.front().second][snake.front().first] = true;

    SpawnFood();

    Uint32 lastUpdateTime = SDL_GetTicks();

    while (isAlive)
    {
        HandleInput();

